a.style:
display: inline;
font-style: normal;
font-size: 16px;
float: left;
margin: 5px 0;
line-height: 25px;
margin-bottom: 25px;
margin-right: 20px;
padding-left: 20px;
text-decoration:none;
color: #000;
background-image: url(/checknotwendig.png);
background-repeat: no-repeat;
background-position: 0px 1px;

body.script:

if(getCookie('_CoverCookies')) {
		$('.slick-track').attr('tabindex','-1');
		$('.slick-slide').attr('tabindex','-1');
		$('.slick-list').attr('tabindex','-1');
}
else {
		$('a').attr('tabindex','-1');
		$('#bfsg_button').attr('tabindex','-1');
		$('#s').attr('tabindex','-1');
		$('#searchsubmit').attr('tabindex','-1');
		$('video').attr('tabindex','-1');
		$('.search-field').attr('tabindex','-1');
		$('#searchform input').attr('tabindex','-1');
		$('#navi_trigger').attr('tabindex','-1');
		$('#stopper-start').attr('tabindex','-1');
		$('#starter-start').attr('tabindex','-1');
		$('#bfsg_close').attr('tabindex','-1');
		$('.slick-track').attr('tabindex','-1');
		$('.slick-slide').attr('tabindex','-1');
		$('.slick-slider').attr('tabindex','-1');
		$('.slick-list').attr('tabindex','-1');
		$('#cookie-headlinea').attr('tabindex','1');
		$('#cookie-headline a').attr('tabindex','1');
		$('#cookie-settings a').attr('tabindex','1');
		$('#aendernlink').attr('tabindex','2');
		$('#dslink').attr('tabindex','3');
		$('#dslink2').attr('tabindex','1');
		$('#aendernlink2').attr('tabindex','1');
		$('#notwendiga').attr('tabindex','1');	
}	


if(getCookie('_CookieDetail')) {
$('#cookie-details').css('display','block');
$('#cookie-headline').css('display','none');
$('#cookie-minitext').css('display','none');
$('#cookie-details-hide').css('display','inline-block');
$('#viewdetails').css('display','none');
} 
else {
$("#viewdetails").click(function() {
setCookie('_CookieDetail','true', 20000);
deleteCookie('_CookieSettings');	
window.location.href = "index.php";
});
}
$("#cookie-details-hide").click(function() {
deleteCookie('_CookieDetail');
deleteCookie('_CookieSettings');
window.location.href = "index.php";
});

if(getCookie('_CookieSettings')) {
$('#cookie-settings').css('display','block');
$('#cookie-headline').css('display','none');
$('#cookie-minitext').css('display','none');
$('#cookie-settings-hide').css('display','inline-block');
$('#viewsettings').css('display','none');	
} 
else {
$("#viewsettings").click(function() {
setCookie('_CookieSettings','true', 20000);
deleteCookie('_CookieDetail');	
window.location.href = "index.php";
});
}
$("#cookie-settings-hide").click(function() {
deleteCookie('_CookieSettings');
deleteCookie('_CookieDetail');
window.location.href = "index.php";
});	

